var currentRoute='';var appRoot=null;var ROUTES={'/':{name:'Home',build:buildHomePage},'/services':{name:'Services',build:buildPlaceholder('Services')},'/led-solutions':{name:'LED Solutions',build:buildPlaceholder('LED Solutions')},'/electrical':{name:'Electrical',build:buildPlaceholder('Electrical')},'/controls':{name:'Controls & Automation',build:buildPlaceholder('Controls & Automation')},'/ev':{name:'EV & Electrification',build:buildPlaceholder('EV & Electrification')},'/diligence':{name:'Diligence & Governance',build:buildPlaceholder('Diligence & Governance')},'/industries':{name:'Industries',build:buildPlaceholder('Industries')},'/about':{name:'About',build:buildPlaceholder('About')},'/case-studies':{name:'Case Studies',build:buildPlaceholder('Case Studies')},'/contact':{name:'Contact',build:buildContactPage}};function getRoute(){var hash=window.location.hash.replace('#','')||'/';if(hash.charAt(0)!=='/')hash='/'+hash;return hash;}
