function updateNavActive(route){var allLinks=document.querySelectorAll('[data-route]');for(var i=0;i<allLinks.length;i++){var link=allLinks[i];var lr=link.getAttribute('data-route');if(lr===route){link.classList.add('es-nav-link-active');link.classList.add('es-mobile-nav-link-active');}else{link.classList.remove('es-nav-link-active');link.classList.remove('es-mobile-nav-link-active');}}}
