function initScrollAnimations(){var items=document.querySelectorAll('.es-fade-in');if(!items.length)return;var observer=new IntersectionObserver(function(entries){entries.forEach(function(entry){if(entry.isIntersecting){entry.target.classList.add('es-visible');observer.unobserve(entry.target);}});},{threshold:0.1,rootMargin:'0px 0px -40px 0px'});for(var i=0;i<items.length;i++){observer.observe(items[i]);}}
