var chatOpen=false;var chatPanel=null;var chatMessages=null;var ELLIE_RESPONSES={'default':"Hey! I'm Ellie Dee, your guide to Energie Solutions. Ask me about our services, coverage area, or how a free audit works.",'hello|hi|hey':"Hey there! How can I help? Ask me about LED retrofits, electrical services, maintenance, or anything else.",'led|lighting|retrofit|lights':"LED retrofits are our bread and butter. We handle the full scope: audit, design, rebate management, and installation. Interior, exterior, high-bay, parking lots \u2014 you name it. The payback is typically 18\u201336 months. Want a free audit?",'electrical|panel|circuit|wiring':"We're a full-service commercial electrical contractor. Panels, circuits, code compliance, emergency repair \u2014 24/7 response available. We handle everything from routine maintenance to major upgrades.",'controls|automation|sensor|scheduling':"Controls & automation are where the long-term savings live. Occupancy sensors, daylight harvesting, scheduling, remote management. We design systems that work for your building, not against your people.",'ev|charging|electrification':"EV charging infrastructure is growing fast. We do load studies, site design, installation, and ongoing management. Whether it's a single Level 2 or a fleet charging depot, we've got you covered.",'diligence|governance|acquisition|buy-side|noi':"Our diligence & governance services are unique. Buy-side intelligence for acquisitions, NOI creation through efficiency, sell-side packaging, and tiered maintenance programs. We speak CRE language.",'maintenance|tier|program':"We offer three tiers of maintenance: reactive (call us when you need us), proactive (scheduled inspections and replacements), and full asset governance (we manage everything). Your building gets better every year.",'pricing|cost|how much|price':"Every building is different, so we don't do cookie-cutter quotes. That's why we start with a free audit \u2014 no cost, no obligation. We'll give you real numbers based on your actual facility.",'area|location|where|birmingham|alabama':"We're based in Birmingham, AL and serve a 3-hour radius: Alabama, Mississippi, Georgia, Florida Panhandle, and Tennessee. Deep local knowledge of utilities, codes, and markets.",'audit|free|assessment':"Our free audit is straightforward: we visit your facility, assess your lighting and electrical systems, identify opportunities, and provide a detailed report with ROI projections. No pressure, no strings. Want to schedule one?",'contact|reach|call|email':"You can reach us at matt@ledsolutions.net or fill out the form on our contact page. We respond within 24 hours.",'rebate|incentive|utility':"We handle rebate management as part of our LED retrofit service. We know the local utility programs inside and out \u2014 Alabama Power, TVA, and others. It's one less thing for you to worry about."};function getEllieDeeResponse(msg){var lower=msg.toLowerCase();var keys=Object.keys(ELLIE_RESPONSES);for(var i=1;i<keys.length;i++){var keywords=keys[i].split('|');for(var j=0;j<keywords.length;j++){if(lower.indexOf(keywords[j])!==-1){return ELLIE_RESPONSES[keys[i]];}}}
return"I'd love to help with that! For specific questions, you can reach us at matt@ledsolutions.net or request a free audit on our contact page. Is there anything else about our services I can help with?";}
function buildChatWidget(){var btn=el('button',{className:'es-chat-btn','aria-label':'Chat with Ellie Dee'});btn.innerHTML=ICONS.chat;var svgBtn=btn.querySelector('svg');if(svgBtn){svgBtn.style.width='24px';svgBtn.style.height='24px';svgBtn.style.color='#fff';}
var pulse=el('div',{className:'es-chat-pulse'});btn.appendChild(pulse);btn.onclick=function(){toggleChat();};document.body.appendChild(btn);chatPanel=el('div',{className:'es-chat-panel'});var header=el('div',{className:'es-chat-header'});var headerTitle=el('span',{className:'es-chat-header-title'});headerTitle.textContent='Ellie Dee';header.appendChild(headerTitle);var closeBtn=el('button',{className:'es-chat-close'});closeBtn.innerHTML=ICONS.close;var svgClose=closeBtn.querySelector('svg');if(svgClose){svgClose.style.width='18px';svgClose.style.height='18px';}
closeBtn.onclick=function(){toggleChat();};header.appendChild(closeBtn);chatPanel.appendChild(header);chatMessages=el('div',{className:'es-chat-messages'});addBotMessage(ELLIE_RESPONSES['default']);chatPanel.appendChild(chatMessages);var inputWrap=el('div',{className:'es-chat-input-wrap'});var input=el('input',{className:'es-chat-input',type:'text',placeholder:'Ask me anything...'});input.id='es-chat-input';input.onkeydown=function(e){if(e.key==='Enter')sendChatMessage();};inputWrap.appendChild(input);var sendBtn=el('button',{className:'es-chat-send'});sendBtn.innerHTML=ICONS.send;var svgSend=sendBtn.querySelector('svg');if(svgSend){svgSend.style.width='16px';svgSend.style.height='16px';svgSend.style.color='#fff';}
sendBtn.onclick=sendChatMessage;inputWrap.appendChild(sendBtn);chatPanel.appendChild(inputWrap);document.body.appendChild(chatPanel);}
function addBotMessage(text){var msg=el('div',{className:'es-chat-msg es-chat-msg-bot'});msg.textContent=text;if(chatMessages)chatMessages.appendChild(msg);scrollChat();}
function addUserMessage(text){var msg=el('div',{className:'es-chat-msg es-chat-msg-user'});msg.textContent=text;if(chatMessages)chatMessages.appendChild(msg);scrollChat();}
function scrollChat(){if(chatMessages){setTimeout(function(){chatMessages.scrollTop=chatMessages.scrollHeight;},50);}}
function sendChatMessage(){var input=document.getElementById('es-chat-input');if(!input||!input.value.trim())return;var msg=input.value.trim();input.value='';addUserMessage(msg);trackEvent('ellie_dee','message',msg);setTimeout(function(){var response=getEllieDeeResponse(msg);addBotMessage(response);},500+Math.random()*500);}
function toggleChat(){chatOpen=!chatOpen;if(chatOpen){chatPanel.classList.add('es-show');trackEvent('ellie_dee','open','');setTimeout(function(){var input=document.getElementById('es-chat-input');if(input)input.focus();},300);}else{chatPanel.classList.remove('es-show');}}
function openChat(){if(!chatOpen)toggleChat();}
var exitShown=false;function initExitIntent(){if('ontouchstart'in window)return;document.addEventListener('mouseout',function(e){if(exitShown)return;if(e.clientY>5)return;if(sessionStorage.getItem('es_exit_shown'))return;showExitIntent();});}
function showExitIntent(){exitShown=true;sessionStorage.setItem('es_exit_shown','1');var overlay=el('div',{className:'es-exit-overlay'});var modal=el('div',{className:'es-exit-modal',style:{position:'relative'}});var close=el('button',{className:'es-exit-close'});close.textContent='\u00D7';close.onclick=function(){overlay.classList.remove('es-show');setTimeout(function(){overlay.remove();},300);};modal.appendChild(close);var boltEl=el('div',{style:{width:'40px',height:'40px',margin:'0 auto 20px',color:RED}});boltEl.innerHTML=ICONS.bolt;var boltSvg=boltEl.querySelector('svg');if(boltSvg){boltSvg.style.width='100%';boltSvg.style.height='100%';}
modal.appendChild(boltEl);var title=el('h3',{className:'es-heading es-exit-title'});title.textContent='Get a Free Audit Before You Go';modal.appendChild(title);var text=el('p',{className:'es-exit-text'});text.textContent="Find out what your building is leaving on the table. It's free, fast, and no-pressure.";modal.appendChild(text);var btn=el('a',{className:'es-btn es-btn-primary',style:{display:'inline-flex'}});btn.textContent='Request Free Audit';btn.onclick=function(e){e.preventDefault();overlay.classList.remove('es-show');setTimeout(function(){overlay.remove();},300);navigateTo('/contact');};modal.appendChild(btn);overlay.appendChild(modal);overlay.onclick=function(e){if(e.target===overlay){overlay.classList.remove('es-show');setTimeout(function(){overlay.remove();},300);}};document.body.appendChild(overlay);trackEvent('exit_intent','show','');requestAnimationFrame(function(){overlay.classList.add('es-show');});}
var toastMessages=['Someone in Birmingham requested a free audit','3 audits scheduled this week','Serving Alabama, Mississippi, Georgia, Tennessee, Florida','New LED retrofit project completed in Huntsville','Free audit requests up this month'];var toastIndex=0;function initToasts(){setTimeout(function(){showToast();setInterval(showToast,45000);},15000);}
function showToast(){var existing=document.querySelector('.es-toast');if(existing)existing.remove();var toast=el('div',{className:'es-toast'});toast.appendChild(el('div',{className:'es-toast-dot'}));toast.appendChild(el('span',null,toastMessages[toastIndex%toastMessages.length]));toastIndex++;document.body.appendChild(toast);requestAnimationFrame(function(){toast.classList.add('es-show');});setTimeout(function(){toast.classList.remove('es-show');setTimeout(function(){toast.remove();},400);},5000);}
function initStickyCTA(){var sticky=el('div',{className:'es-sticky-cta'});var btn=el('button',{className:'es-sticky-cta-btn'});btn.textContent='Get Free Audit';btn.onclick=function(){navigateTo('/contact');};sticky.appendChild(btn);document.body.appendChild(sticky);window.addEventListener('scroll',throttle(function(){var y=window.scrollY||window.pageYOffset;if(y>window.innerHeight*0.8){sticky.classList.add('es-show');}else{sticky.classList.remove('es-show');}},150));}
function initScrollTracking(){var depths=[25,50,75,100];var tracked={};window.addEventListener('scroll',throttle(function(){var scrollHeight=document.documentElement.scrollHeight-window.innerHeight;if(scrollHeight<=0)return;var pct=Math.round(((window.scrollY||window.pageYOffset)/scrollHeight)*100);depths.forEach(function(d){if(pct>=d&&!tracked[d]){tracked[d]=true;trackEvent('scroll','depth',d+'%');}});},500));}
function init(){loadFonts();injectStyles();document.body.appendChild(buildNav());document.body.appendChild(buildMobileNav());initScrollNav();appRoot=el('div',{className:'es-page',id:'es-app'});document.body.appendChild(appRoot);window.addEventListener('hashchange',handleRoute);handleRoute();buildChatWidget();initExitIntent();initToasts();initStickyCTA();initScrollTracking();trackEvent('session','start','visit_'+visitCount);}
